def calculate_discounted_cash_flow(cash_flows_list, rate):
    discounted_value = sum(cf / ((1 + rate) ** (i + 1)) for i, cf in enumerate(cash_flows_list))
    return discounted_value

def compute(inputs):
    cash_flows = inputs['cash_flows']
    discount_rate = inputs['discount_rate']
    initial_investment = inputs['initial_investment']

    discounted_cash_flows = calculate_discounted_cash_flow(cash_flows, discount_rate)
    net_present_value = discounted_cash_flows - initial_investment

